import java.util.*;

public class PageRequest {
    private final int page;    // 0-based
    private final int size;
    private final String sortBy;

    public PageRequest(int page, int size, String sortBy) {
        this.page = page; this.size = size; this.sortBy = sortBy;
    }

    public int getPage() { return page; }
    public int getSize() { return size; }
    public String getSortBy() { return sortBy; }
    public int getOffset() { return page * size; }
}

public class Page<T> {
    private final List<T> content;
    private final long totalElements;
    private final int pageNumber;
    private final int pageSize;

    public Page(List<T> content, long totalElements, int pageNumber, int pageSize) {
        this.content = content; this.totalElements = totalElements;
        this.pageNumber = pageNumber; this.pageSize = pageSize;
    }

    public List<T> getContent() { return content; }
    public long getTotalElements() { return totalElements; }
    public int getTotalPages() { return (int) Math.ceil((double) totalElements / pageSize); }
    public boolean hasNext() { return pageNumber < getTotalPages() - 1; }

    @Override
    public String toString() {
        return "Page " + (pageNumber+1) + "/" + getTotalPages() + ": " + content;
    }
}

